472	  \label{thm:Scheme_module_finite_globalSections_of_isProper}
473	  \lean{AlgebraicGeometry.Scheme.module_finite_globalSections_of_isProper}
474	  \uses{def:Scheme_kToSection, def:Scheme_algebraSection, thm:Scheme_toModuleKSheaf}
475	  Let $k$ be a field and $C$ an integral scheme over $\Spec k$ with proper structure morphism. Then $\Gamma(C, \mathcal O_C)$ is finite-dimensional over $k$.
476	\end{theorem}
