478	\begin{proof}
479	  \uses{def:Scheme_kToSection, def:Scheme_algebraSection}
480	  \leanok
481	  Apply the theorem that for an integral scheme with a universally closed, locally finite-type morphism to $\Spec k$, the structure-morphism ring map on global sections is module-finite. Transfer the base ring from $\Gamma(\Spec k, \top)$ to $k$ along the canonical ring isomorphism.
482	\end{proof}
